        // Resolve all A/AAAA records; if any are non-public, block.
        InetAddress[] addrs = InetAddress.getAllByName(host);
        if (addrs == null || addrs.length == 0) {
            throw new URISyntaxException(host, "Host does not resolve");
        }

        for (InetAddress addr : addrs) {
