        if (addr instanceof Inet6Address) {
            byte[] b = addr.getAddress();

            // Unique local addresses: fc00::/7 (fc00..fdff)
            int first = b[0] & 0xFF;
            if ((first & 0xFE) == 0xFC) {
                return false;
            }

            // IPv4-mapped IPv6 ::ffff:0:0/96 -> validate mapped IPv4 too
            if (isIpv4Mapped(b)) {
                byte[] v4 = new byte[]{b[12], b[13], b[14], b[15]};
                try {
                    InetAddress v4Addr = InetAddress.getByAddress(v4);
                    return isPublicAddress(v4Addr);
                } catch (Exception ignored) {
                    return false;
                }
            }
        }

        // Additional IPv4 checks for ranges not covered by isSiteLocalAddress()
        if (addr instanceof Inet4Address) {
            byte[] b = addr.getAddress();
            int a = b[0] & 0xFF;
            int c = b[1] & 0xFF;

            // 100.64.0.0/10 (CGNAT)
            if (a == 100 && (c >= 64 && c <= 127)) {
                return false;
            }
            // 169.254.0.0/16 (link-local) already covered by isLinkLocalAddress, kept for clarity
            // 127.0.0.0/8 already covered by isLoopbackAddress
            // 0.0.0.0/8 (this network)
            if (a == 0) {
                return false;
            }
            // 192.0.0.0/24 (IETF Protocol Assignments)
            if (a == 192 && c == 0 && (b[2] & 0xFF) == 0) {
                return false;
            }
            // 192.0.2.0/24, 198.51.100.0/24, 203.0.113.0/24 (TEST-NET)
            int d = b[2] & 0xFF;
            if ((a == 192 && c == 0 && d == 2)
                    || (a == 198 && c == 51 && d == 100)
                    || (a == 203 && c == 0 && d == 113)) {
                return false;
            }
            // 224.0.0.0/4 multicast already covered by isMulticastAddress
            // 240.0.0.0/4 reserved
            if (a >= 240) {
                return false;
            }
        }

        return true;
    }

    private static boolean isIpv4Mapped(byte[] ipv6) {
        if (ipv6 == null || ipv6.length != 16) return false;
        for (int i = 0; i < 10; i++) {
            if (ipv6[i] != 0x00) return false;
        }
        return (ipv6[10] == (byte) 0xFF && ipv6[11] == (byte) 0xFF);
    }
}

